import React from "react";

const AdminUsers = () => {
  const users = [
    { id: 1, name: "John", email: "john@gmail.com" },
    { id: 2, name: "Sara", email: "sara@gmail.com" },
  ];

  return (
    <>
      <h1>Users</h1>

      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Email</th>
          </tr>
        </thead>

        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.name}</td>
              <td>{u.email}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );
};

export default AdminUsers;
